ที่มีสีสันครบถ้วนจึงมักจะถูกละเว้น เพื่อไม่ให้ความสนใจของผู้ใช้และทีมงานถูกเบี่ยงเบนไปจากโครงสร้างหลัก.", "indexInBatch": 17}, {"id": "ux-idea-4-b0-019", "tags": ["Wireframe", "Modals", "UI Components", "wireframe-components"], "type": "comparison", "answer": "a", "prompt": "เมื่อออกแบบ Wireframe สำหรับ Modal (ป๊อปอัป) แสดงข้อความยืนยันการลบ คุณจะเลือกแบบใดที่สื่อสารความตั้งใจได้อย่างชัดเจน?", "content": {"options": [{"id": "a", "label": "แบบ A", "content": "<div class=\"fixed inset-0 bg-gray-600 bg-opacity-50 flex items-center justify-center\"><div class=\"bg-white p-6 rounded-lg shadow-xl max-w-sm w-full space-y-4\"><h3 class=\"text-lg font-bold text-gray-900\">ยืนยันการลบ</h3><p class=\"text-gray-700 text-sm\">คุณแน่ใจหรือไม่ว่าต้องการลบรายการนี้? การดำเนินการนี้ไม่สามารถย้อนกลับได้</p><div class=\"flex justify-end space-x-2\"><button class=\"px-4 py-2 text-sm font-medium text-gray-700 bg-gray-200 rounded-md hover:bg-gray-300\">ยกเลิก</button><button class=\"px-4 py-2 text-sm font-medium text-white bg-red-600 rounded-md hover:bg-red-700\">ลบ</button></div></div></div>", "previewClasses": "p-4 flex justify-center items-center h-48 bg-white"}, {"id": "b", "label": "แบบ B", "content": "<div class=\"fixed inset-0 bg-gray-600 bg-opacity-50 flex items-center justify-center\"><div class=\"bg-white p-6 rounded-lg shadow-xl max-w-sm w-full space-y-4\"><div class=\"h-6 bg-gray-200 rounded w-3/4\"></div><div class=\"h-12 bg-gray-100 rounded w-full\"></div><div class=\"flex justify-end space-x-2\"><div class=\"h-8 w-20 bg-gray-300 rounded\"></div><div class=\"h-8 w-16 bg-gray-400 rounded\"></div></div></div></div>", "previewClasses": "p-4 flex justify-center items-center h-48 bg-white"}]}, "courseId": "ux-ideation", "moduleId": "ux-idea-4", "batchIndex": 0, "difficulty": 2, "explanation": "Modal ควรมีหัวข้อที่ชัดเจน, ข้อความอธิบายที่เข้าใจง่าย และปุ่มสำหรับดำเนินการที่สื่อถึงการกระทำนั้นๆ ตัวเลือก A มีข้อความและปุ่มที่ชัดเจน ทำให้ผู้ใช้เข้าใจได้ทันทีว่าเป็นการยืนยันการลบ ในข